// UpdateNewValues updates the mutable fields using the new values that
// were set on create. Using this option is equivalent to using:
//
//	client.SnapshotEntry.Create().
//		OnConflict(
//			sql.ResolveWithNewValues(),
//		).
//		Exec(ctx)
func (u *SnapshotEntryUpsertBulk) UpdateNewValues() *SnapshotEntryUpsertBulk {
	u.create.conflict = append(u.create.conflict, sql.ResolveWithNewValues())
	u.create.conflict = append(u.create.conflict, sql.ResolveWith(func(s *sql.UpdateSet) {
		for _, b := range u.create.builders {
			if _, exists := b.mutation.HouseholdID(); exists {
				s.SetIgnore(snapshotentry.FieldHouseholdID)
			}
			if _, exists := b.mutation.CreateTime(); exists {
				s.SetIgnore(snapshotentry.FieldCreateTime)
			}
			if _, exists := b.mutation.Liquidity(); exists {
				s.SetIgnore(snapshotentry.FieldLiquidity)
			}
			if _, exists := b.mutation.Investment(); exists {
				s.SetIgnore(snapshotentry.FieldInvestment)
			}
			if _, exists := b.mutation.Property(); exists {
				s.SetIgnore(snapshotentry.FieldProperty)
			}
			if _, exists := b.mutation.Receivable(); exists {
				s.SetIgnore(snapshotentry.FieldReceivable)
			}
			if _, exists := b.mutation.Liability(); exists {
				s.SetIgnore(snapshotentry.FieldLiability)
			}
			if _, exists := b.mutation.HouseholdCurrencyID(); exists {
				s.SetIgnore(snapshotentry.FieldHouseholdCurrencyID)
			}
			if _, exists := b.mutation.UserID(); exists {
				s.SetIgnore(snapshotentry.FieldUserID)
			}
			if _, exists := b.mutation.SnapshotID(); exists {
				s.SetIgnore(snapshotentry.FieldSnapshotID)
			}
		}
	}))
	return u
}

// Ignore sets each column to itself in case of conflict.
// Using this option is equivalent to using:
//
//	client.SnapshotEntry.Create().
